use note_match_lab::{status_line, Note, NoteState};

fn note(state: NoteState) -> Note {
    Note { title: String::from("T"), body: String::from("B"), state }
}

#[test]
fn handles_draft() {
    assert_eq!(status_line(&note(NoteState::Draft)), "draft");
}

#[test]
fn handles_published() {
    assert_eq!(status_line(&note(NoteState::Published { published_at: String::from("today") })), "published at today");
}

#[test]
fn handles_archived() {
    assert_eq!(status_line(&note(NoteState::Archived { reason: String::from("duplicate") })), "archived: duplicate");
}
